import{_ as t}from"./chunks/微笑狼的公开仓库.gGdYP2E_.js";import{_ as e,o as d,c as i,a2 as o}from"./chunks/framework.DnrXFDHb.js";const b=JSON.parse('{"title":"Автоматичне додавання тегів","description":"","frontmatter":{},"headers":[],"relativePath":"uk-UA/Other/auto-tagging.md","filePath":"uk-UA/Other/auto-tagging.md","lastUpdated":1781962217000}'),s={name:"uk-UA/Other/auto-tagging.md"};function n(c,a,l,p,r,g){return d(),i("div",null,[...a[0]||(a[0]=[o('<h1 id="автоматичне-додавання-тегів" tabindex="-1">Автоматичне додавання тегів <a class="header-anchor" href="#автоматичне-додавання-тегів" aria-label="Permalink to &quot;Автоматичне додавання тегів&quot;">​</a></h1><p>Auto tagging налаштовується тут:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Other Settings -&gt; Auto Tagging</span></span></code></pre></div><p>Функція автоматично генерує теги для зображень. Вони корисні для пошуку, фільтрації random image, публічної галереї та контролю доступу за віковим рейтингом.</p><h2 id="що-може-auto-tagging" tabindex="-1">Що може Auto Tagging <a class="header-anchor" href="#що-може-auto-tagging" aria-label="Permalink to &quot;Що може Auto Tagging&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Можливість</th><th>Опис</th></tr></thead><tbody><tr><td>Генерація content tags</td><td>Додає теги для людей, сцен, об&#39;єктів, стилю ілюстрації та схожого візуального змісту.</td></tr><tr><td>Генерація character tags</td><td>Корисно для anime-зображень та ілюстрацій.</td></tr><tr><td>Додавання orientation tags</td><td>Додає <code>landscape</code>, <code>portrait</code> або <code>square</code>.</td></tr><tr><td>Додавання rating</td><td>Зберігає результати <code>G/S/Q/E</code> для general, sensitive, questionable або explicit content.</td></tr><tr><td>Auto-tag on upload</td><td>Нові зображення автоматично потрапляють у процес тегування.</td></tr><tr><td>Batch tagging</td><td>Додає теги до старих зображень у всіх папках або в обраних папках.</td></tr></tbody></table><h2 id="що-підготувати-спочатку" tabindex="-1">Що підготувати спочатку <a class="header-anchor" href="#що-підготувати-спочатку" aria-label="Permalink to &quot;Що підготувати спочатку&quot;">​</a></h2><p>Потрібен принаймні один доступний URL Hugging Face Space.</p><p>Рекомендований варіант — зробити копію Space SmilingWolf <code>wd-tagger</code> у власний акаунт Hugging Face:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://huggingface.co/spaces/SmilingWolf/wd-tagger</span></span></code></pre></div><p>Публічний Space можна використати для тимчасового тестування, але ним користується багато людей, тому можливі черги, повільна робота або недоступність. Копія у власному акаунті зазвичай стабільніша для постійного auto tagging.</p><h2 id="дублювання-space-smilingwolf" tabindex="-1">Дублювання Space SmilingWolf <a class="header-anchor" href="#дублювання-space-smilingwolf" aria-label="Permalink to &quot;Дублювання Space SmilingWolf&quot;">​</a></h2><ol><li>Увійдіть у Hugging Face.</li><li>Відкрийте <code>https://huggingface.co/spaces/SmilingWolf/wd-tagger</code>.</li></ol><p><img src="'+t+`" alt="Публічний Space SmilingWolf" loading="lazy"></p><ol start="3"><li>Натисніть меню з трьома крапками у правому верхньому куті.</li><li>Виберіть <code>Duplicate this Space</code>.</li><li>Залиште стандартну назву Space або задайте власну, наприклад <code>wd-tagger</code>.</li><li>Встановіть visibility як <code>Public</code>. Public Spaces простіше викликати з ImgBed.</li><li>Спочатку залиште безплатне hardware. Переходьте на сильніше тільки тоді, коли черги стають помітними.</li><li>Створіть Space і дочекайтеся завершення build.</li></ol><p>Після завершення build відкрийте сторінку свого Space. URL зазвичай має такий вигляд:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://huggingface.co/spaces/your-name/wd-tagger</span></span></code></pre></div><p>Скопіюйте адресу з браузера й вставте її в ImgBed у <code>Space URLs</code>.</p><h2 id="додавання-кількох-space-urls" tabindex="-1">Додавання кількох Space URLs <a class="header-anchor" href="#додавання-кількох-space-urls" aria-label="Permalink to &quot;Додавання кількох Space URLs&quot;">​</a></h2><p>Вводьте по одному Space URL на рядок.</p><table tabindex="0"><thead><tr><th>Значення</th><th>Опис</th></tr></thead><tbody><tr><td><code>https://huggingface.co/spaces/SmilingWolf/wd-tagger</code></td><td>Публічний Space SmilingWolf. Добре для тимчасового тесту.</td></tr><tr><td><code>https://huggingface.co/spaces/lintonxue00/wd-tagger</code></td><td>URL сторінки скопійованого Space.</td></tr><tr><td><code>https://huggingface.co/spaces/your-name/wd-tagger</code></td><td>Ваш власний дубльований Space.</td></tr></tbody></table><p>Можна вказати кілька URL. ImgBed використовує кілька Spaces разом, що може підвищити швидкість.</p><p>Якщо один Space тимчасово недоступний, інші можуть продовжити обробку.</p><h2 id="налаштування" tabindex="-1">Налаштування <a class="header-anchor" href="#налаштування" aria-label="Permalink to &quot;Налаштування&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Опція</th><th>Рекомендація</th></tr></thead><tbody><tr><td><code>Space URLs</code></td><td>Введіть підготовлені Space URLs. Потрібен щонайменше один.</td></tr><tr><td>Target folder</td><td>Залиште порожнім для всіх папок. Вибирайте папку лише тоді, коли треба обробити конкретну директорію.</td></tr><tr><td>Recognition model</td><td>Типово залиште <code>wd-swinv2-tagger-v3</code>.</td></tr><tr><td>General tag threshold</td><td>Типове значення підходить для більшості зображень. Нижче значення дає більше тегів, вище — менше.</td></tr><tr><td>Character tag threshold</td><td>Типове значення доволі обережне й допомагає уникати неправильних character tags.</td></tr><tr><td><code>MCut</code> automatic threshold</td><td>Спочатку залиште вимкненим. Увімкніть, коли хочете, щоб модель сама визначала кількість тегів.</td></tr><tr><td>Auto-tag on upload</td><td>Увімкніть, якщо нові зображення мають отримувати теги автоматично.</td></tr><tr><td>Start tagging</td><td>Запускає ручне batch tagging для старих зображень.</td></tr></tbody></table><h2 id="рекомендовані-стартові-значення" tabindex="-1">Рекомендовані стартові значення <a class="header-anchor" href="#рекомендовані-стартові-значення" aria-label="Permalink to &quot;Рекомендовані стартові значення&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Опція</th><th>Рекомендоване значення</th></tr></thead><tbody><tr><td>Recognition model</td><td><code>wd-swinv2-tagger-v3</code></td></tr><tr><td>General tag threshold</td><td><code>0.35</code></td></tr><tr><td>Character tag threshold</td><td><code>0.85</code></td></tr><tr><td><code>MCut</code></td><td>Спочатку Off</td></tr><tr><td>Auto-tag on upload</td><td>Увімкнути за потреби</td></tr></tbody></table><p>Якщо тегів забагато, трохи підніміть general threshold.</p><p>Якщо тегів замало, трохи знизьте general threshold.</p><h2 id="batch-tagging" tabindex="-1">Batch Tagging <a class="header-anchor" href="#batch-tagging" aria-label="Permalink to &quot;Batch Tagging&quot;">​</a></h2><ol><li>Заповніть <code>Space URLs</code>.</li><li>Виберіть target folder.</li><li>Натисніть start tagging.</li><li>Дочекайтеся завершення прогресу.</li></ol><p>Якщо target folder порожній, ImgBed обробляє всі папки.</p><p>Batch tagging найкраще підходить для старих зображень. Для нових увімкніть auto-tag on upload, щоб не запускати процес вручну щоразу.</p><h2 id="auto-tag-on-upload" tabindex="-1">Auto-Tag on Upload <a class="header-anchor" href="#auto-tag-on-upload" aria-label="Permalink to &quot;Auto-Tag on Upload&quot;">​</a></h2><p>Після ввімкнення auto-tag on upload нові зображення автоматично викликають налаштовані <code>Space URLs</code>.</p><p>Це зручно для постійного використання.</p><p>Якщо ваш Space стоїть у черзі, саме завантаження все одно може завершитися першим, а тегування продовжиться після нього.</p><h2 id="які-зображення-обробляються" tabindex="-1">Які зображення обробляються <a class="header-anchor" href="#які-зображення-обробляються" aria-label="Permalink to &quot;Які зображення обробляються&quot;">​</a></h2><p>Auto tagging переважно обробляє файли зображень.</p><p>Зображення, які вже мають повні tags, orientation, rating, width і height, пропускаються, щоб не викликати Space зайвий раз.</p><p>ImgBed за можливості доповнює тільки відсутню інформацію. Наприклад, якщо бракує лише orientation, він спробує додати orientation без повного content tag flow.</p><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="навіщо-дублювати-власнии-space" tabindex="-1">Навіщо дублювати власний Space? <a class="header-anchor" href="#навіщо-дублювати-власнии-space" aria-label="Permalink to &quot;Навіщо дублювати власний Space?&quot;">​</a></h3><p>Публічні Spaces спільні для багатьох користувачів. Власний дубльований Space переважно використовує тільки ваш ImgBed, тому він зазвичай швидший і надійніший.</p><h3 id="space-постіино-запускається" tabindex="-1">Space постійно запускається <a class="header-anchor" href="#space-постіино-запускається" aria-label="Permalink to &quot;Space постійно запускається&quot;">​</a></h3><p>Після першого створення або довгого простою Space може потребувати часу на старт.</p><p>Спершу відкрийте сторінку свого Space. Коли він нормально розпізнає зображення, поверніться до ImgBed і запускайте тегування.</p><h3 id="як-скопіювати-space-url" tabindex="-1">Як скопіювати Space URL? <a class="header-anchor" href="#як-скопіювати-space-url" aria-label="Permalink to &quot;Як скопіювати Space URL?&quot;">​</a></h3><p>Відкрийте сторінку Hugging Face Space і скопіюйте адресу з браузера.</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://huggingface.co/spaces/lintonxue00/wd-tagger</span></span>
<span class="line"><span>https://huggingface.co/spaces/SmilingWolf/wd-tagger</span></span></code></pre></div><h3 id="чи-можна-додати-кілька-spaces" tabindex="-1">Чи можна додати кілька Spaces? <a class="header-anchor" href="#чи-можна-додати-кілька-spaces" aria-label="Permalink to &quot;Чи можна додати кілька Spaces?&quot;">​</a></h3><p>Так. Вводьте по одному Space URL на рядок.</p><p>Кілька Spaces обробляють зображення разом і корисні, коли файлів багато.</p><h3 id="чому-теги-англіиською" tabindex="-1">Чому теги англійською? <a class="header-anchor" href="#чому-теги-англіиською" aria-label="Permalink to &quot;Чому теги англійською?&quot;">​</a></h3><p>Моделі SmilingWolf повертають англомовні теги. Це очікувана поведінка.</p><p>Ці теги використовуються переважно для пошуку, фільтрів, random image API та публічної галереї.</p><h3 id="для-чого-потрібні-rating-tags" tabindex="-1">Для чого потрібні rating tags? <a class="header-anchor" href="#для-чого-потрібні-rating-tags" aria-label="Permalink to &quot;Для чого потрібні rating tags?&quot;">​</a></h3><p>Результати rating працюють разом з access mode у Security Settings.</p><p>Наприклад, коли доступ відвідувачів обмежений віковим рейтингом, публічний перегляд і random image фільтрують зображення за цими правилами.</p><h2 id="короткии-сценаріи" tabindex="-1">Короткий сценарій <a class="header-anchor" href="#короткии-сценаріи" aria-label="Permalink to &quot;Короткий сценарій&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Увійти в Hugging Face</span></span>
<span class="line"><span>-&gt; Відкрити SmilingWolf/wd-tagger</span></span>
<span class="line"><span>-&gt; Duplicate this Space</span></span>
<span class="line"><span>-&gt; Дочекатися build Space</span></span>
<span class="line"><span>-&gt; Скопіювати Space URL</span></span>
<span class="line"><span>-&gt; Заповнити Space URLs в ImgBed</span></span>
<span class="line"><span>-&gt; Вибрати модель і thresholds</span></span>
<span class="line"><span>-&gt; Запустити tagging або ввімкнути auto-tag on upload</span></span></code></pre></div>`,61)])])}const m=e(s,[["render",n]]);export{b as __pageData,m as default};
